  "inlineSchema": "datasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\nmodel User {\n  id         String   @id @default(uuid())\n  username   String   @unique\n  password   String\n  role       String   @default(\"JUDGE\")\n  name       String\n  isChairman Boolean  @default(false)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n  scores     Score[]\n}\n\nmodel Candidate {\n  id        String                   @id @default(uuid())\n  number    Int                      @unique\n  firstName String\n  lastName  String\n  bio       String?\n  avatarUrl String?\n  createdAt DateTime                 @default(now())\n  updatedAt DateTime                 @updatedAt\n  scores    Score[]\n  votes     AudienceVote[]\n  snapshots ScoreAnalyticsSnapshot[]\n}\n\nmodel PageantSection {\n  id          String     @id @default(uuid())\n  name        String     @unique // e.g., Swimwear, Evening Gown, Q&A\n  weight      Float // e.g., 0.3 for 30%\n  description String?\n  isActive    Boolean    @default(true)\n  criteria    Criteria[]\n  scores      Score[]\n}\n\nmodel Criteria {\n  id               String         @id @default(uuid())\n  pageantSectionId String\n  name             String // e.g., Poise, Beauty, Confidence\n  maxPoints        Float // e.g., 100\n  weight           Float // e.g., 0.4 for 40% of the section\n  section          PageantSection @relation(fields: [pageantSectionId], references: [id], onDelete: Cascade)\n  scores           ScoreDetail[]\n}\n\nmodel Score {\n  id                  String         @id @default(uuid())\n  judgeId             String\n  candidateId         String\n  pageantSectionId    String\n  computedScore       Float // Total weighted score for this section\n  isSyncedFromOffline Boolean        @default(false)\n  createdAt           DateTime       @default(now())\n  updatedAt           DateTime       @updatedAt\n  judge               User           @relation(fields: [judgeId], references: [id])\n  candidate           Candidate      @relation(fields: [candidateId], references: [id])\n  section             PageantSection @relation(fields: [pageantSectionId], references: [id])\n  details             ScoreDetail[]\n\n  @@unique([judgeId, candidateId, pageantSectionId])\n}\n\nmodel ScoreDetail {\n  id         String   @id @default(uuid())\n  scoreId    String\n  criteriaId String\n  points     Float // Raw points awarded\n  score      Score    @relation(fields: [scoreId], references: [id], onDelete: Cascade)\n  criteria   Criteria @relation(fields: [criteriaId], references: [id])\n}\n\nmodel AudienceVote {\n  id          String    @id @default(uuid())\n  candidateId String\n  deviceId    String // Hashed fingerprint or device id\n  voteDate    DateTime  @default(now()) // Stored date to check limit\n  candidate   Candidate @relation(fields: [candidateId], references: [id])\n\n  @@unique([deviceId, candidateId]) // Prevent multi-voting by the same device for the same candidate\n}\n\nmodel OfflineScoreQueue {\n  id        String   @id @default(uuid())\n  judgeId   String\n  payload   String\n  synced    Boolean  @default(false)\n  createdAt DateTime @default(now())\n}\n\nmodel ScoreAnalyticsSnapshot {\n  id           String    @id @default(uuid())\n  candidateId  String\n  sectionId    String\n  totalScore   Float\n  rankPosition Int\n  computedAt   DateTime  @default(now())\n  candidate    Candidate @relation(fields: [candidateId], references: [id])\n}\n\nmodel QRVoteSession {\n  id          String   @id @default(uuid())\n  qrCodeToken String   @unique\n  expiresAt   DateTime\n  isActive    Boolean  @default(true)\n}\n\nmodel SystemSetting {\n  id    String @id @default(uuid())\n  key   String @unique\n  value String\n}\n",
